INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Multiple question types$q$, $q$Multiple choice, checkboxes, dropdowns, short answer, paragraph text, linear scale, grids, date/time, and file upload questions cover most common form needs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Quiz mode with auto-grading$q$, $q$Any form can be turned into a graded quiz with point values, answer keys, and automatic scoring and feedback.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Themes and light customization$q$, $q$Basic controls for color, font, and header images let creators adjust the look of a form without design skills.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Automatic response collection$q$, $q$Submissions can flow directly into a linked Google Sheet or be viewed in a built-in summary with response charts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Real-time collaborative editing$q$, $q$Multiple people can build and edit the same form simultaneously, similar to how Google Docs handles shared editing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Sections and branching logic$q$, $q$Forms can be split into sections with skip logic that routes respondents to different questions based on prior answers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Response validation$q$, $q$Field-level validation rules (such as number ranges or text length) help ensure submitted data is in the expected format.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Add-ons and Apps Script extensibility$q$, $q$Google Workspace Marketplace add-ons and Apps Script allow custom automation like notification emails or third-party integrations.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Template gallery$q$, $q$Pre-built templates for RSVPs, feedback surveys, quizzes, and event registration speed up form creation.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Flexible sharing options$q$, $q$Forms can be shared via direct link, email invitation, embedded iframe, or social sharing buttons.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Completely free to use with no feature paywall for core form and survey functionality$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Very easy to learn, with almost no setup or onboarding required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Tight integration with Google Sheets, Drive, and Google Classroom$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Real-time collaborative editing lets multiple people build a form together$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Works reliably on mobile devices and only requires a Google account to use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Limited design and branding customization compared to dedicated survey tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$No native payment collection for orders or ticket sales$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Basic analytics and reporting compared to paid survey platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Ties form creation and data storage to a Google account and the Google ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Conditional logic is limited to simple section-based branching, not complex multi-path flows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Is Google Forms free to use?$q$, $q$Yes. Google Forms is free for anyone with a Google account, with no paid tier required to access its core form, survey, and quiz features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Can I create quizzes in Google Forms?$q$, $q$Yes. Forms has a built-in quiz mode that supports point values, answer keys, and automatic grading, commonly used by teachers for assessments.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Where do Google Forms responses go?$q$, $q$Responses can be viewed in a built-in summary tab with charts, or exported automatically to a linked Google Sheet for further analysis.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Can Google Forms collect payments?$q$, $q$Not natively. Google Forms does not include built-in payment processing, so orders or paid registrations typically require a separate payment tool or add-on.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Does Google Forms work offline?$q$, $q$Form creators need an internet connection to build and edit forms, and respondents generally need a connection to submit answers, since there is no dedicated offline collection app.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Classroom quizzes and assessments$q$, $q$Teachers build graded quizzes with auto-scoring and distribute them through Google Classroom, cutting grading time on objective questions.$q$, $q$Teachers and educational institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Event RSVP and registration$q$, $q$Organizers collect attendee names, headcounts, and preferences through a shareable link, with responses tracked in a spreadsheet.$q$, $q$Event organizers and community groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Customer feedback surveys$q$, $q$Small businesses gather feedback after a purchase or service visit using a simple, no-cost survey linked from email or receipts.$q$, $q$Small business owners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Internal team surveys and polls$q$, $q$Teams run quick internal polls or intake forms for scheduling, requests, or feedback without needing new software approval.$q$, $q$Internal teams and HR departments$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Personal (Free)$q$, $q$Free$q$, $q$N/A$q$, $q$["Unlimited forms and surveys","All core question types","Quiz mode with auto-grading","Responses synced to Google Sheets","Real-time collaborative editing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Business Starter$q$, $q$From $6 per user/month$q$, $q$Monthly, billed annually$q$, $q$["Google Forms included as part of Google Workspace","Business email and additional Drive storage","Basic admin and security controls","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Business Standard$q$, $q$From $12 per user/month$q$, $q$Monthly, billed annually$q$, $q$["Everything in Business Starter","Increased Drive storage per user","Additional Meet and collaboration features","Enhanced admin controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$Business Plus$q$, $q$From $18 per user/month$q$, $q$Monthly, billed annually$q$, $q$["Everything in Business Standard","Advanced security and compliance controls","eDiscovery and retention tools","Enhanced endpoint management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Forms is a free, web-based tool for creating online forms, surveys, and quizzes. Launched in 2008 as part of the Google Docs suite, it has grown into one of the most widely used survey tools in the world simply because it is free, fast to set up, and tied directly into Google's other products.$q$, $q$A form is built from a list of questions — multiple choice, checkboxes, dropdowns, short answer, paragraph text, linear scale, grids, date and time pickers, and file uploads — arranged with drag-and-drop reordering. Once published, a form can be shared via a link, embedded on a website, or sent by email, and every submission lands automatically in a connected Google Sheet or in a built-in response summary with charts.$q$, $q$Compared to dedicated survey platforms like Typeform or SurveyMonkey, Google Forms trades polish and advanced logic for simplicity and cost: there is no paid tier required to unlock core functionality, and anyone with a Google account can start building a form in minutes without training or a design background.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$who-its-for$q$, $q$Who Google Forms Is For$q$, 2, ARRAY[$q$Teachers and instructors are among the heaviest users, relying on Forms for quizzes, exit tickets, and assignments, especially where it connects directly into Google Classroom for grading and distribution. The built-in quiz mode with auto-grading and answer keys makes it a practical, no-cost alternative to dedicated assessment software.$q$, $q$Small businesses, freelancers, and event organizers use Forms for everyday tasks like RSVP collection, customer feedback, order intake, and simple registration forms, since it requires no setup cost and integrates cleanly with spreadsheets they likely already use for tracking.$q$, $q$It also suits individuals, nonprofits, student groups, and researchers running informal surveys or one-off data collection projects, where the goal is to gather structured responses quickly without budgeting for survey software licensing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need heavy branding control, white-labeled surveys, or highly customized visual design will find Forms limiting — theming options are basic compared to tools built specifically for branded customer-facing surveys.$q$, $q$Organizations needing advanced conditional logic across many branching paths, native payment collection, multi-channel distribution analytics, or deep integrations with CRMs like Salesforce or HubSpot are usually better served by dedicated platforms such as Typeform, SurveyMonkey, or Jotform, which are purpose-built for those workflows.$q$, $q$Users who need offline data collection in the field, complex multi-step approval workflows, or enterprise-grade reporting and segmentation will also hit ceilings quickly, since those capabilities require external tools, Google Apps Script customization, or third-party add-ons rather than being available natively.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Forms supports a wide range of question types, response validation rules, required-field settings, and section-based branching (skip logic) that routes respondents to different parts of a form based on their answers, covering most needs for surveys, quizzes, and simple applications.$q$, $q$Quiz mode turns any form into a graded assessment with point values, automatic scoring, and feedback per answer, while themes let creators adjust colors, fonts, and header images for basic visual consistency. Forms also supports real-time collaborative editing, so multiple people can build or review a form together, similar to Google Docs.$q$, $q$Responses can flow directly into Google Sheets for analysis, be reviewed in an aggregated summary view with charts, or be extended through Google Workspace Marketplace add-ons and Apps Script for things like automated emails, advanced validation, or third-party integrations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db6b7ee1-78f4-46e7-8173-0f395de936ba', $q$the-google-forms-experience$q$, $q$The Google Forms Experience$q$, 2, ARRAY[$q$The interface is intentionally minimal: a single-column editor, live preview, and a small set of formatting controls. There is very little onboarding needed — most users can build their first form within a few minutes of opening it, without documentation or tutorials.$q$, $q$Forms are responsive by default and render well on phones and tablets, and Google's Forms mobile app for iOS and Android lets creators check incoming responses on the go, though most building still happens through the browser rather than the app.$q$, $q$Overall, the experience favors speed and reliability over depth: it rarely breaks, saves automatically, and plugs directly into Drive, Sheets, and Classroom, which is why it remains a default choice for quick, low-stakes data collection even among users who also pay for more advanced survey tools.$q$]::text[], 4);
