INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Multimodal chat$q$, $q$Understands and responds to text, images, PDFs, and (on paid tiers) audio and video within a single conversation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Gemini Live$q$, $q$Real-time, interruptible voice conversations with the assistant, designed for hands-free, natural back-and-forth dialogue.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Large context window$q$, $q$Can process very long documents, transcripts, or codebases in a single prompt without losing earlier context.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Google Workspace integration$q$, $q$Works directly inside Gmail, Docs, Sheets, Slides, and Drive to draft, summarize, and analyze content in place.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Deep Research$q$, $q$An agentic research mode that browses multiple web sources and compiles findings into a structured written report.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Image generation and editing$q$, $q$Creates and edits images from text prompts directly within the chat interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Custom Gems$q$, $q$User-configurable assistant personas with saved instructions for recurring, specialized tasks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Android system integration$q$, $q$Acts as a system-level assistant on Android, able to read on-screen content and take actions inside other apps.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Developer API and Vertex AI access$q$, $q$Exposes Gemini models through the Gemini API and Google Cloud's Vertex AI for building custom applications.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Deep, native integration with Gmail, Docs, Sheets, and other Google Workspace apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Large context window handles long documents, transcripts, and codebases well$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Usable free tier with no cost of entry before deciding to subscribe$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Strong voice experience through Gemini Live for hands-free use$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Flexible developer access via API and Vertex AI with usage-based pricing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Advantages are strongest for users already inside the Google ecosystem$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Closed model family with no open-weight or self-hostable option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Can still produce inaccurate or outdated answers like any large language model$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Premium features and higher usage limits are locked behind paid subscriptions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Feature set and naming have changed frequently, which can be confusing to track$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Is Google Gemini free to use?$q$, $q$Yes, Gemini offers a free tier with access to the assistant and a base model. Higher usage limits, more advanced models, and extra features like expanded Workspace integration require a Google AI Pro or Google AI Ultra subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$What happened to Google Bard?$q$, $q$Bard was Google's original AI chatbot, launched in 2023. In February 2024, Google renamed and relaunched it as Gemini to align the assistant with its underlying Gemini model family.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Can developers build with Gemini models?$q$, $q$Yes. Gemini models are available to developers through the Gemini API and Google Cloud's Vertex AI, with usage-based pricing based on tokens processed rather than a flat subscription.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Does Gemini work inside Gmail and Docs?$q$, $q$Yes. Gemini is integrated directly into Google Workspace apps such as Gmail, Docs, Sheets, and Slides, letting users draft, summarize, and analyze content without leaving the app.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$What is Gemini Live?$q$, $q$Gemini Live is a real-time voice conversation mode that lets users talk to the assistant naturally, including interrupting it mid-response, similar to a phone call rather than typed chat.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Drafting and editing documents$q$, $q$Generate outlines, rewrite drafts, and adjust tone directly inside Google Docs without switching to a separate app.$q$, $q$Professionals and students writing reports, emails, or essays$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Inbox and calendar triage$q$, $q$Summarize long email threads and draft quick replies directly within Gmail.$q$, $q$Busy professionals managing high email volume$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Research synthesis$q$, $q$Use Deep Research to gather information from multiple web sources and compile it into a single structured report.$q$, $q$Students, analysts, and researchers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$In-app development assistance$q$, $q$Call Gemini models through the API or Vertex AI to add multimodal reasoning, summarization, or code assistance to a custom application.$q$, $q$Software developers and product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["Access to a base Gemini model","Standard response and usage limits","Access via web, Android, and iOS apps","Basic Workspace integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Google AI Pro$q$, $q$$19.99/month$q$, $q$Monthly$q$, $q$["Higher usage limits than the free tier","Access to more advanced Gemini models","Expanded Workspace integration (Gmail, Docs, Sheets, Slides)","Bundled Google One cloud storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$Google AI Ultra$q$, $q$$249.99/month$q$, $q$Monthly$q$, $q$["Highest usage limits and priority access to the most capable models","Early access to new experimental features","Expanded Workspace integration and Deep Research allowance","Largest bundled Google One storage tier"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Gemini is Google's family of multimodal AI models and the consumer chat assistant built on top of them, accessible at gemini.google.com and through dedicated Android and iOS apps. The assistant started life as Bard in 2023 and was renamed Gemini in February 2024 to match the underlying model line, bringing a steady stream of new capabilities such as real-time voice conversation, native image generation, and deeper integration across Google's own products.$q$, $q$Under the hood, Gemini models are designed from the ground up to reason across text, images, audio, video, and code rather than bolting multimodal support onto a text-only base. Different model sizes (broadly split into faster, cheaper variants and larger, more capable ones) power different surfaces: the web and mobile chat app, on-device features on Pixel and other Android phones, Search's AI-generated overviews, and enterprise tools through Google Cloud.$q$, $q$Gemini competes directly with OpenAI's ChatGPT, Anthropic's Claude, and Microsoft Copilot. Its main differentiators are tight integration with Gmail, Docs, Sheets, and Drive, very large context windows that let it work with lengthy documents or codebases in one pass, and a single account that spans free consumer use, paid subscriptions, and pay-as-you-go developer access through Google AI Studio and Vertex AI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$who-its-for$q$, $q$Who Google Gemini Is For$q$, 2, ARRAY[$q$Gemini fits naturally for people already living inside Google Workspace. Anyone drafting in Docs, triaging Gmail, or building spreadsheets in Sheets can call on Gemini without switching tools, which makes it a practical choice for professionals, small business owners, and teams that have standardized on Google's productivity suite rather than Microsoft 365.$q$, $q$It also suits Android users who want an assistant woven into the operating system itself, replacing the older Google Assistant for tasks like summarizing notifications, drafting replies, or controlling apps by voice through Gemini Live. Students and researchers benefit from features like Deep Research, which can work through many web sources to compile a longer report, and from the large context window that accommodates long PDFs, lecture notes, or datasets.$q$, $q$Developers and technical teams are a strong fit too, since Gemini models are exposed through the Gemini API and Vertex AI with usage-based pricing, letting engineers embed multimodal reasoning into their own apps. Budget-conscious individuals who want a genuinely usable free tier before deciding whether to pay for a premium assistant are also well served.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$People who are uncomfortable with a single company holding both their AI conversations and their email, documents, and search history in one ecosystem may prefer a provider with a narrower product footprint. Gemini's usefulness is closely tied to being inside Google's stack, so its advantages shrink for anyone who intentionally avoids that ecosystem.$q$, $q$Teams standardized on Microsoft 365 will generally get a smoother experience from Copilot, since deep integration with Outlook, Word, and Excel favors Microsoft's assistant over Gemini. Developers who specifically need an open-weight or self-hostable model for offline, air-gapped, or fully customizable deployments should also look elsewhere, since Gemini is a closed, cloud-hosted model family.$q$, $q$Users who have found that Gemini's answers are inconsistent for their particular niche, or who prefer a smaller, more specialized tool over a broad general-purpose assistant, may be better served by a dedicated writing, coding, or research product rather than a do-everything assistant.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Gemini offers a conversational chat interface that handles text, uploaded images, PDFs, and, on paid tiers, video and audio. Gemini Live adds a natural, interruptible voice conversation mode, and image generation lets users create and edit pictures directly from a prompt within the same chat thread.$q$, $q$Workspace integration is a headline feature: Gemini can draft and refine documents in Docs, summarize threads and draft replies in Gmail, build formulas and analyze data in Sheets, and generate slide outlines in Slides, all from a side panel. Custom "Gems" let users configure a saved assistant persona with its own instructions for recurring tasks, and Deep Research mode autonomously browses multiple sources to assemble a longer written report.$q$, $q$On Android, Gemini is embedded as a system-level assistant that can act on-screen inside other apps, while Gemini for Google Cloud, Google AI Studio, and Vertex AI give developers programmatic access to the same models for building custom applications, complete with large context windows suited to long documents or codebases.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', $q$the-experience$q$, $q$The Google Gemini Experience$q$, 2, ARRAY[$q$Day to day, using Gemini feels similar to other major AI chat apps: a clean chat window, a prompt box that accepts text, files, and images, and a running history of past conversations. What sets the experience apart is how often it nudges toward other Google surfaces, offering to open a result directly in Docs or Sheets, or to pull in a Gmail thread for context.$q$, $q$The mobile app leans on voice more than most competitors, with Gemini Live positioned as a hands-free companion rather than just a fallback input method, and on supported Android phones the assistant can take actions inside other apps rather than only replying in its own window.$q$, $q$Response quality is generally strong for research, summarization, and everyday writing, though like all large language models it can occasionally produce inaccurate or outdated information, so users doing high-stakes research or coding still benefit from verifying important claims and citations before relying on them.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1769cc92-bed0-46a8-9354-2d81fdae9ad4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Unified Omnichannel Inbox$q$, $q$Combines email, live chat, Instagram and Facebook messages, SMS, and voice into a single ticket queue instead of separate tools per channel.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Native Order and Customer Data$q$, $q$Pulls Shopify (and BigCommerce/Magento/WooCommerce) order history, shipment tracking, and customer details directly into the ticket view.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Macros with Dynamic Variables$q$, $q$Templated responses that auto-fill live details like order number, tracking link, or customer name rather than sending static text.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Automation Rules$q$, $q$Rule-based logic to tag, route, and auto-close routine tickets such as shipping-status questions without agent involvement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI Agent$q$, $q$A GPT-based assistant that acts as both a pre-sale shopping assistant and a post-sale support agent on Shopify, able to answer questions and execute actions like refunds or order edits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Convert Live Chat$q$, $q$An on-site chat widget aimed at engaging high-intent shoppers and lifting conversion, not just answering support questions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Revenue Statistics$q$, $q$Reporting that attributes sales to specific support conversations, channels, or agents to show the commercial impact of customer service.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Multi-Store and Multi-Brand Management$q$, $q$Connects multiple stores or brands to a single Gorgias account for centralized ticket routing and reporting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Integrations Marketplace$q$, $q$Pre-built connections to e-commerce tools such as Klaviyo, Yotpo, Loop Returns, Recharge, and Aircall.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Self-Service Help Center$q$, $q$A customer-facing knowledge base that also supplies the content the AI Agent draws on to answer questions automatically.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Deep, native Shopify integration puts order and customer data directly inside every ticket$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI Agent can take real actions, like issuing refunds or editing orders, not just draft replies$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Revenue Statistics ties support conversations back to actual sales, making the case for support investment easier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Unlimited agent seats on Pro and Advanced plans, so cost doesn't scale simply from adding more people$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Wide library of e-commerce-specific integrations for loyalty, reviews, subscriptions, and calling$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Ticket-based pricing can become expensive and harder to predict for high-volume or fast-growing stores$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$The AI Agent's most powerful automated actions are built around Shopify, so BigCommerce, Magento, and WooCommerce merchants get a lighter version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$AI Agent resolutions are billed separately per conversation on top of the ticket fee, adding a second cost to track$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Getting meaningful automation gains requires upfront setup, such as help center content and tuned rules, rather than working well immediately out of the box$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Less suited to non-e-commerce support use cases than general-purpose helpdesks$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$What is Gorgias used for?$q$, $q$Gorgias is a helpdesk built for e-commerce brands to manage customer support across email, live chat, social media, and SMS, with order and customer data pulled directly into each ticket.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Does Gorgias integrate with Shopify?$q$, $q$Yes. Shopify is Gorgias's deepest integration, surfacing orders, customers, and store data natively inside tickets and powering the AI Agent's automated actions. BigCommerce, Magento, and WooCommerce are also supported at the core helpdesk level.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$How is Gorgias priced?$q$, $q$Plans are based on the number of billable tickets, meaning customer-initiated conversations an agent views or responds to, handled per month, ranging from a Starter plan for smaller stores up to custom Enterprise pricing for high-volume merchants. The AI Agent is billed separately per resolved conversation.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Does Gorgias offer a free trial?$q$, $q$Yes, Gorgias offers a free trial so merchants can test the helpdesk and automation features against their own real ticket volume before choosing a plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$What does the Gorgias AI Agent actually do?$q$, $q$It can answer common customer questions using a store's help center content and past tickets, and on Shopify stores it can also perform actions such as issuing a refund or modifying an order, rather than only drafting a reply for a human to review.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Reducing Order-Status Tickets$q$, $q$Automation rules and the AI Agent auto-resolve routine shipping and order-status questions using live tracking data instead of routing them to a human agent.$q$, $q$Shopify stores with high post-purchase ticket volume$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Attributing Revenue to Customer Support$q$, $q$Revenue Statistics tracks which conversations, agents, or channels are associated with a purchase, letting stores treat support as a measurable growth channel.$q$, $q$E-commerce brands wanting to justify support headcount with revenue data$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Consolidating Multi-Channel Support$q$, $q$Merges email, live chat, Instagram and Facebook messages, and SMS into one inbox for stores previously juggling several separate support tools.$q$, $q$Growing DTC brands expanding into new support channels$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Managing Support Across Multiple Stores or Clients$q$, $q$Agencies and multi-brand retailers use a single Gorgias account to route tickets and view reporting across several connected stores.$q$, $q$Agencies and multi-brand e-commerce operators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Starter$q$, $q$$10/month$q$, $q$Monthly$q$, $q$["50 billable tickets per month included","3 agent seats","Core helpdesk: email, chat, and social channels","Overage billed at $0.40 per ticket beyond the included limit"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Basic$q$, $q$$60/month (discounted with annual billing)$q$, $q$Monthly or annual$q$, $q$["300 billable tickets per month included","Shopify, BigCommerce, Magento, and WooCommerce integrations","Macros with order-data variables","Overage billed at $0.40 per ticket"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Pro$q$, $q$$360/month (discounted with annual billing)$q$, $q$Monthly or annual$q$, $q$["2,000 billable tickets per month included","Unlimited agent seats","Convert live chat and automation rules","Revenue Statistics reporting","Overage billed at $0.36 per ticket"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$Advanced$q$, $q$$900/month (discounted with annual billing)$q$, $q$Monthly or annual$q$, $q$["5,000 billable tickets per month included","Unlimited agent seats","Advanced automation and priority support","AI Agent available, billed per resolution","Overage billed at $0.36 per ticket"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gorgias is a customer support platform built specifically for e-commerce businesses, founded in 2015 and headquartered in San Francisco. Rather than being a general-purpose helpdesk, it is designed around the workflows of online stores, connecting directly to Shopify and, to a lesser extent, BigCommerce, Magento (Adobe Commerce), and WooCommerce, so agents can see order, customer, and shipment details without leaving the ticket.$q$, $q$The product treats every support conversation as a potential sales or retention moment rather than pure overhead. Order history, tracking status, subscription details, and loyalty data appear alongside the message thread, and features like Revenue Statistics attempt to quantify how much revenue support conversations influence, reframing the help desk as a channel that can pay for itself rather than a pure cost center.$q$, $q$Gorgias has expanded from an email- and chat-based helpdesk into a broader suite that includes on-site live chat (Convert), rule-based automation, and an AI Agent that can answer questions and take store actions on its own. It is used by a large number of e-commerce brands, with the deepest integration and most automated features reserved for stores running on Shopify.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$who-gorgias-is-for$q$, $q$Who Gorgias Is For$q$, 2, ARRAY[$q$Gorgias is built for direct-to-consumer and e-commerce brands, and the fit is strongest for merchants on Shopify, where the integration and AI Agent automation are most complete. Brands fielding a steady stream of repetitive questions, such as order status, returns, sizing, or subscription changes, are well positioned to benefit from macros and automation rules that handle these without a human touching every ticket.$q$, $q$It works for support teams ranging from a single founder answering tickets to larger, multi-agent teams, since higher-tier plans include unlimited agent seats and the platform can manage multiple connected stores or brands from one account. Teams that want to demonstrate the commercial value of customer support, not just track resolution times, are a good match for the built-in revenue reporting.$q$, $q$Agencies and consultants supporting several e-commerce clients also find value here, since Gorgias plugs into many of the retention and marketing tools those clients already run, such as loyalty, reviews, and subscription apps, letting support data flow into the rest of the commerce stack instead of sitting in isolation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Companies outside of e-commerce, such as B2B software vendors, service businesses, or internal IT and HR helpdesks, generally will not benefit from Gorgias's order-centric design, since much of its value depends on commerce-platform data like orders, carts, and shipments that simply doesn't exist in those contexts. A general-purpose helpdesk is usually a better fit there.$q$, $q$Merchants on platforms other than Shopify should also go in with clear expectations: the core helpdesk works with BigCommerce, Magento, and WooCommerce, but the AI Agent's automated actions are built specifically around Shopify, so non-Shopify stores get a narrower automation experience than the marketing might suggest.$q$, $q$Very small stores with only a handful of tickets a month may find the ticket-based billing awkward to plan around, since a temporary spike in support volume from a sale, a shipping delay, or a viral product can push a store into overage charges or a higher plan faster than a flat-fee tool would.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The center of the product is a shared inbox that combines email, live chat, Instagram and Facebook messages, SMS, and voice into a single ticket queue, with automation rules handling tagging, routing, and closing out repetitive requests. Macros insert live variables, such as an order number, tracking link, or customer name, instead of static canned text.$q$, $q$The AI Agent, Gorgias's most-promoted feature, works in two modes on Shopify stores: as a shopping assistant that helps visitors find and choose products before a sale, and as a support agent that resolves post-purchase questions and can carry out actions like issuing a refund or updating an order end to end, without a human needing to touch the ticket.$q$, $q$Convert, the on-site chat widget, is built to engage high-intent visitors and lift conversion rather than just answer questions, while Revenue Statistics reports which channels, agents, or automations are associated with the most sales. An app marketplace connects Gorgias to tools such as Klaviyo, Yotpo, Loop Returns, Recharge, and Aircall.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', $q$the-gorgias-experience$q$, $q$The Gorgias Experience$q$, 2, ARRAY[$q$In daily use, agents work from one ticket screen with customer and order details in a side panel, so a shipping question rarely requires opening a separate admin tab. Teams switching from a generic helpdesk typically notice this as the biggest change to their day-to-day workflow.$q$, $q$Getting full value out of Gorgias takes some setup work: connecting the store, writing help center content the AI Agent can draw on, and testing automation rules before letting them run unsupervised on real customers. Stores that invest this time tend to see the clearest drop in per-ticket handling time.$q$, $q$Because billing is based on ticket volume, and the AI Agent is billed per resolution on top of the ticket fee, growing stores should watch their usage and plan for cost as both order volume and automation use increase. The free trial is a useful way to gauge real ticket counts before committing to a plan.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
