INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('421bda78-e5b8-4973-86a7-1481632d297e', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$HD video and audio conferencing$q$, $q$Host meetings with high-definition video and clear audio for participants joining from a browser, desktop app, or mobile device.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Screen sharing$q$, $q$Share a full desktop, single application window, or browser tab so participants can follow a presentation, demo, or document review.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Smart Meeting Assistant (AI transcription and summaries)$q$, $q$Automatically records meetings, generates transcripts, and produces AI-written summaries that highlight key topics and action items.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Cloud recording$q$, $q$Record sessions to the cloud so they can be reviewed, shared, or transcribed after the meeting ends without local storage management.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Drawing and annotation tools$q$, $q$Mark up a shared screen in real time with pointers, shapes, and freehand drawing to guide participants through a walkthrough.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Personal meeting room$q$, $q$Every organizer gets a fixed, reusable meeting link and dial-in number, so recurring meetings don't need a new invite each time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Admin and security controls$q$, $q$Company admins can manage organizer licenses, lock meetings, control entry, and review account-wide usage from a central dashboard.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Mobile and desktop apps$q$, $q$Native apps for Windows, Mac, iOS, and Android let hosts and participants start or join meetings without relying on a browser.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Calendar integrations$q$, $q$Schedule and launch meetings directly from Outlook or Google Calendar without switching between separate scheduling tools.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$One of the most established, reliable video conferencing products, with a long track record for call stability$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Smart Meeting Assistant provides useful AI transcripts and summaries without needing a separate note-taking tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Simple, low-friction joining experience for guests, including browser-based join and phone dial-in options$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Fits naturally into the broader GoTo Connect suite for businesses already using GoTo for phone or IT support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Centralized admin controls make it easier to manage licenses and security across larger organizer counts$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$No permanent free plan, only a time-limited free trial, unlike several competing video conferencing tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Entry-level Professional plan caps participants at 50, which is limiting for larger team meetings$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Not designed for large public webinars or virtual events, which require GoTo's separate webinar product$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Interface feels dated next to newer collaboration-first tools with deeper chat and whiteboard features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Less tightly integrated into Microsoft Teams or Google Workspace than each platform's own native meeting tool$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Does GoTo Meeting have a free plan?$q$, $q$No. GoTo Meeting does not offer a permanent free tier; it offers a 14-day free trial of its paid plans, after which a Professional, Business, or Enterprise subscription is required to keep hosting meetings.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$How many people can join a GoTo Meeting session?$q$, $q$Capacity depends on the plan: the Professional plan supports up to 50 participants, the Business plan up to 250, and the Enterprise plan up to 3,000 participants per meeting.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Does GoTo Meeting include AI transcription and meeting summaries?$q$, $q$Yes. Its Smart Meeting Assistant automatically records and transcribes meetings and generates an AI summary highlighting key discussion points and action items, included with Business and Enterprise plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Is GoTo Meeting the same product as GoTo Webinar?$q$, $q$No. GoTo Meeting is designed for standard meetings and client calls, while GoTo Webinar is a separate product built for large-scale webinars with registration pages and audience marketing tools.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$What platforms does GoTo Meeting run on?$q$, $q$GoTo Meeting is available through a web browser and has dedicated desktop apps for Windows and Mac, plus mobile apps for iOS and Android.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Client and sales calls$q$, $q$Sales reps and consultants use GoTo Meeting's personal meeting rooms and dial-in numbers to run professional, no-download-required calls with prospects and clients.$q$, $q$Sales teams and client-facing consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Recurring internal team meetings$q$, $q$Teams schedule standing meetings through calendar integrations and rely on the Smart Meeting Assistant to keep a searchable record of decisions and action items.$q$, $q$Small and mid-sized business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Remote training and walkthroughs$q$, $q$Trainers and support staff use screen sharing and annotation tools to walk participants through software, documents, or processes step by step.$q$, $q$Training and customer support teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Unified communications alongside GoTo Connect$q$, $q$Companies already using GoTo Connect for business phone service add GoTo Meeting to manage phone, meetings, and support under one vendor and admin console.$q$, $q$IT administrators managing company-wide communications$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Professional$q$, $q$$12 per organizer/month$q$, $q$Billed annually$q$, $q$["Up to 50 participants per meeting","HD video and audio conferencing","Screen sharing and drawing tools","Personal meeting room","Cloud recording"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Business$q$, $q$$16 per organizer/month$q$, $q$Billed annually$q$, $q$["Up to 250 participants per meeting","Smart Meeting Assistant (AI transcripts and summaries)","Everything in Professional","Meeting insights and reporting","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, $q$["Up to 3,000 participants per meeting","Dedicated Customer Success Manager","Onboarding and training assistance","Volume-based discounting","Advanced admin and security controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoTo Meeting is a cloud-based video conferencing and online meeting platform built by GoTo, the company formerly known as LogMeIn and, before that, part of Citrix Online. Launched in 2004 as GoToMeeting, it is one of the oldest web conferencing products still actively sold today, predating most of the video call tools now common in modern offices. Following GoTo's 2022 corporate rebrand, GoTo Meeting became the dedicated meetings component of the wider GoTo Connect unified communications suite, sitting alongside GoTo's phone system and IT support products.$q$, $q$At its core, GoTo Meeting provides HD video and audio conferencing, screen sharing, and a browser- or app-based join flow for hosting internal meetings, client calls, and small group collaboration sessions. Every organizer gets a personal meeting room with a reusable link, and meetings can include a built-in Smart Meeting Assistant that records, transcribes, and summarizes what was discussed, along with drawing and annotation tools for walking participants through a shared screen.$q$, $q$Compared with all-in-one platforms like Zoom or Microsoft Teams, GoTo Meeting is a narrower, more focused product. It doesn't attempt to be a full collaboration hub with persistent chat channels or document storage, and it has no permanent free tier. Instead, it leans on reliability, quick setup, and tight integration with GoTo's other communication tools, which makes it most relevant to organizations already using, or planning to adopt, GoTo Connect for phone service or GoTo Resolve for remote IT support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$who-goto-meeting-is-for$q$, $q$Who GoTo Meeting Is For$q$, 2, ARRAY[$q$GoTo Meeting fits small and mid-sized businesses that want a straightforward, no-frills video conferencing tool rather than a sprawling collaboration suite. It's a natural fit for organizations already running GoTo Connect for business phone service, since meetings, calling, and contact center features can be managed under one vendor and one admin console instead of stitching together separate platforms.$q$, $q$Sales teams, consultants, and client-facing service providers are a strong match, since GoTo Meeting was built around external, one-off calls rather than internal team chat. Features like dial-in conference numbers, a professional-looking join screen, and no-download joining for guests matter more to people meeting with prospects and clients than to teams that live in a single always-on workspace.$q$, $q$IT administrators and operations teams also benefit from GoTo Meeting's centralized admin controls, which let them provision organizer accounts, enforce meeting security settings, and pull usage reporting across departments. For companies that need a predictable, centrally managed video tool for dozens or hundreds of employees, that administrative layer is often a bigger draw than any single meeting feature.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Anyone looking for a permanently free video calling tool should look elsewhere. Unlike Zoom, Google Meet, or Microsoft Teams, GoTo Meeting has no free-forever plan, only a 14-day free trial, so occasional users or very small teams with tight budgets will find the ongoing per-organizer cost harder to justify.$q$, $q$Organizations planning large public webinars or virtual events are also better served by a different product. GoTo sells GoTo Webinar as a separate offering for registration pages, audience marketing, and large one-to-many broadcasts; GoTo Meeting is built for meetings, not managed webinar programs, even though its higher tiers support larger participant counts.$q$, $q$Teams that are fully standardized on Microsoft 365 or Google Workspace and want video conferencing woven directly into that ecosystem's chat, calendar, and file-sharing may prefer Teams or Meet instead. GoTo Meeting does offer calendar integrations, but it operates as a separate application rather than a native extension of either ecosystem.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$GoTo Meeting's core experience centers on HD video and audio conferencing with screen sharing, so a host can present a document, browser tab, or full desktop to participants joining from a browser, the desktop app, or a mobile device. Drawing and annotation tools let presenters highlight or mark up what's on screen in real time during a walkthrough or demo.$q$, $q$The Smart Meeting Assistant is the product's most distinctive capability: it automatically records sessions to the cloud, generates a transcript, and produces an AI summary that surfaces discussion highlights and action items, which can then be shared with attendees who missed the call. Every organizer also gets a fixed personal meeting room URL, so recurring meetings don't require sending out a new link each time.$q$, $q$On the administrative side, company admins can manage organizer licenses, set meeting locking and entry controls, and view account-wide usage from a central dashboard. Dial-in conference numbers cover audio-only participants, and desktop and mobile apps for Windows, Mac, iOS, and Android let hosts start or join meetings without needing a browser.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', $q$the-goto-meeting-experience$q$, $q$The GoTo Meeting Experience$q$, 2, ARRAY[$q$Joining a GoTo Meeting session is deliberately low-friction: guests can click a meeting link and join from a browser without creating an account or installing anything, or dial in from a phone if they don't have a reliable internet connection. Hosts typically launch their fixed personal meeting room or schedule a session through a calendar integration with Outlook or Google Calendar.$q$, $q$Day to day, the host experience revolves around starting a call, sharing a screen for a demo or walkthrough, and letting the Smart Meeting Assistant handle recording and note-taking in the background. After the call ends, the AI-generated summary and transcript are available in the account, so a salesperson or support rep can review commitments made during the meeting without re-watching the recording.$q$, $q$Overall, the experience favors dependability and simplicity over novelty. Long-time users often describe it as a stable, no-surprises tool for external calls, though its interface feels less modern than newer entrants, and it lacks the persistent team-chat and whiteboard depth found in broader collaboration suites.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
