INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c6868389-8d0e-4fab-b74c-b58f1badba46', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$AI detection score$q$, $q$Analyzes submitted text and returns a prediction of how likely it is to be human-written, AI-generated, or a mix of both.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Sentence-level highlighting$q$, $q$Highlights specific sentences or passages that the model flags as most likely AI-generated, giving reviewers more context than a single overall score.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Mixed-authorship detection$q$, $q$Attempts to identify documents that combine human writing with AI-generated or AI-edited sections, rather than treating a document as purely one or the other.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Plagiarism checker$q$, $q$Compares submitted text against web and academic sources to surface potential plagiarism alongside the AI-detection results.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Chrome extension$q$, $q$Adds AI-detection checks directly in the browser, so users don't need to copy and paste text into the main web app for a quick scan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Batch document scanning$q$, $q$Lets paid users upload and check multiple documents at once, useful for instructors or reviewers handling many submissions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Classroom/team dashboard$q$, $q$Organizes past scans and submissions for instructors or teams managing recurring reviews, rather than treating each check as a one-off.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$API access$q$, $q$Available on higher-tier plans for organizations that want to integrate AI-content detection into their own applications or review workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$LMS-oriented integrations$q$, $q$Supports workflows aimed at learning management platforms used in schools, positioning detection closer to where assignments are actually submitted.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$One of the earliest and most recognized names in AI-text detection, with a large base of educators familiar with the tool$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Sentence-level highlighting gives more actionable context than a single yes/no verdict$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Combines AI detection with a plagiarism checker in one product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Simple, fast interface that doesn't require technical knowledge to interpret results$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Classroom-oriented dashboard and batch scanning make it practical for reviewing many student submissions$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Like all AI detectors, it can produce false positives, flagging genuine human writing as AI-generated$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$It can also produce false negatives, especially when AI text has been paraphrased or lightly edited$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Detection accuracy is not guaranteed and results should not be treated as definitive proof$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Free plan usage is limited, and heavier or bulk use requires a paid subscription$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Non-native-English writers or highly formulaic writing styles may be more prone to inaccurate flags$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$What does GPTZero actually detect?$q$, $q$GPTZero analyzes text and estimates the likelihood that it was written by a human, generated by an AI model, or a mix of both, and highlights the sentences it considers most AI-like.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Is GPTZero's AI detection 100% accurate?$q$, $q$No. Like every AI-text detector on the market, GPTZero's results are probabilistic and can include both false positives and false negatives, so scores should be treated as one input rather than definitive proof.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Is GPTZero free to use?$q$, $q$GPTZero offers a free plan with limited usage. Paid Essential, Premium, and Professional plans add higher word limits, batch scanning, and features like API access, and custom pricing is available for classrooms and enterprise teams.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Who created GPTZero?$q$, $q$GPTZero was created in January 2023 by Edward Tian, who was a Princeton University student at the time, in direct response to the rise of AI writing tools like ChatGPT.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Can GPTZero be fooled by paraphrasing tools?$q$, $q$Detection accuracy can drop when AI-generated text is paraphrased or edited before submission, which is a known limitation shared across AI-detection tools generally, not just GPTZero.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Checking student essay submissions$q$, $q$Instructors run submitted essays or homework through GPTZero to get a signal on possible AI involvement before deciding whether further discussion with the student is warranted.$q$, $q$Teachers and professors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Academic integrity review at scale$q$, $q$Departments or academic-integrity offices use batch scanning to review many submissions across a class or program rather than checking documents one at a time.$q$, $q$Academic institutions and administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Editorial screening of submitted content$q$, $q$Publishers and content editors use GPTZero as an initial screen on freelance or user-submitted articles to flag pieces that may need closer editorial review.$q$, $q$Publishers and content teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Application and cover letter screening$q$, $q$Admissions or hiring teams use AI-detection scores as one signal among several when reviewing application essays or cover letters submitted at scale.$q$, $q$Admissions offices and hiring teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Basic$q$, $q$$0$q$, $q$Free$q$, $q$["Limited monthly word count for AI detection","Core AI detection score","Sentence-level highlighting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Essential$q$, $q$~$10-15/month depending on billing cycle$q$, $q$Monthly or annual$q$, $q$["Higher monthly word limit","AI detection and plagiarism checking","Chrome extension access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Premium$q$, $q$~$16-24/month depending on billing cycle$q$, $q$Monthly or annual$q$, $q$["Increased word limits over Essential","Priority processing","Expanded reporting detail"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$Professional / Educator / Enterprise$q$, $q$Custom / higher tier pricing, contact sales for teams$q$, $q$Monthly, annual, or custom$q$, $q$["Largest word-count allowances","API access","Classroom or team management dashboard","Custom per-seat pricing for larger organizations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GPTZero is an AI content detection tool built to identify whether a piece of text was written by a human or generated (fully or partly) by a large language model such as ChatGPT. It was launched in January 2023 by Edward Tian, then a Princeton University student studying computer science and journalism, making it one of the earliest widely recognized AI-detection products to reach mainstream attention after ChatGPT's public debut.$q$, $q$The core product analyzes submitted text and returns a prediction of how likely it is to be AI-generated, human-written, or a mix of both, along with sentence-level highlighting meant to show which parts of a document look most machine-like. Under the hood, detectors like this generally rely on statistical signals in language patterns, such as predictability and variation in sentence structure, rather than any kind of definitive fingerprint, since AI-generated text has no built-in watermark that reliably survives editing or paraphrasing.$q$, $q$GPTZero has grown from a single-purpose classroom tool into a broader platform that also includes a plagiarism checker, a Chrome extension, and integrations aimed at schools and organizations that need to review large volumes of written submissions. It remains best known, however, for its original use case: giving educators a way to flag student writing that may warrant a closer look, and its early launch gave it significant name recognition compared with detectors that arrived later in the market.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$who-gptzero-is-for$q$, $q$Who GPTZero Is For$q$, 2, ARRAY[$q$Teachers, professors, and academic departments are the clearest fit for GPTZero. Its interface, reporting, and messaging are built around the workflow of reviewing student essays, homework, and exam responses, and many schools have adopted it (or a similar detector) as part of academic-integrity policies introduced after generative AI became widely available.$q$, $q$Beyond education, GPTZero is also used by publishers, content editors, and hiring managers who want a first-pass signal on whether submitted writing (articles, cover letters, application essays) may have been produced with heavy AI assistance. For these users it functions as a screening tool rather than a final verdict.$q$, $q$Admissions offices and organizations that process large volumes of applicant or student writing may also find value in the batch-scanning and reporting features, since manually reading every submission for AI involvement isn't practical at scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Anyone who needs a legally or academically airtight determination should be cautious. Like every AI detector on the market, GPTZero's predictions are probabilistic, not proof. False positives (human writing flagged as AI) and false negatives (AI writing that slips through, especially after paraphrasing) are well-documented limitations across this entire product category, and using a single detector score to accuse someone of misconduct without corroborating evidence carries real risk to students or employees, including reputational and academic consequences that can be hard to reverse.$q$, $q$Users who write in a plain, formulaic, or non-native-English style may also be more prone to false flags, since detectors often key off of predictability and sentence-level uniformity, traits that can appear in careful human writing as well as machine output. Institutions relying on GPTZero as the sole basis for disciplinary action, rather than one input among several, should reconsider that approach.$q$, $q$People who need unlimited high-volume scanning on a tight budget may also find the free tier too limited for their needs, since word-count caps apply and heavier use requires a paid plan.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$GPTZero's central feature is its AI detection score, delivered alongside sentence- and paragraph-level highlighting that indicates which portions of a document are most likely AI-generated. It also attempts to flag mixed-authorship text, where a document contains both human-written and AI-generated sections, which is common when writers use AI tools to draft or polish parts of their work.$q$, $q$The platform includes a plagiarism checker that compares submitted text against web and academic sources, a writing report feature intended to give instructors more context than a single score, and a Chrome browser extension for quicker checks outside the main web app. Paid plans add higher word-count limits, batch document uploads, and team or classroom management tools for reviewing many submissions at once, which matters for anyone processing more than a handful of documents per month.$q$, $q$For organizations that want to build detection into their own workflows, GPTZero also offers API access on its higher-tier plans, along with integrations aimed at learning management systems used in schools, which lets the detection step happen closer to where assignments are actually submitted rather than requiring a separate manual upload for every document.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', $q$the-gptzero-experience$q$, $q$The GPTZero Experience$q$, 2, ARRAY[$q$Using GPTZero is straightforward: paste text or upload a document, and the tool returns a score and highlighted breakdown within seconds. The interface favors clarity over jargon, presenting results in plain language rather than raw statistical output, which makes it accessible to educators who aren't technical.$q$, $q$For instructors managing multiple classes, the dashboard experience adds structure around what would otherwise be a one-off check, letting them review submissions in bulk, organize them by class or assignment, and revisit past scans rather than re-uploading files each time. That workflow-oriented design is a big part of why schools have adopted it over simply pasting text into a generic checker.$q$, $q$The overall experience is fast and easy to learn, but it's most useful when treated as a starting point rather than a conclusion. GPTZero itself and independent reviewers alike acknowledge that detection scores can be wrong in either direction, so the tool works best paired with human judgment, a conversation with the writer, or additional evidence before any decision is made.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b09d10-a6f8-417d-b1b5-3f44cf179e0c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
